  return {
    type: 'default',
    bgColor: 'INTENSE_COLOR_01',
    titleColor: 'BRAND_COMPLEMENT_01',
    isSelected: true,
    leftIcon: transaction.icon,
    leftIconColor: 'BRAND_COMPLEMENT_01',
    showBackgroundLeftIcon: true,
    title: capitalizedDescription,
    value: '+ 150 pontos' or '- 500 pontos',
    valueColor: 'PLUS_COLOR_02' or 'BRAND_COMPLEMENT_01',
    descriptionSecondary: 'Ganhos' | 'Usados' | 'Expirados',
    descriptionSecondaryColor: 'INTENSE_COLOR_04',
    showIcon: true,
    rightIcon: 'icon-next',
    showRightIcon: !isExpired,
    onPressDetail: () => { /* analytics */ },
    label: '20 de fevereiro',  // Date header
    showLabel: true,           // Only first item per day
  };
}
```

