}

function TransactionsList({
  items,
  isLoading,
}: {
  items: propsItemsListCardTransition[];
  isLoading: boolean;
}) {
  return (
    <ListCardTransition
      items={items}
      isLoading={isLoading}
      scrollEnabled={false}
      mb="meddium"
    />
