import { chromium } from 'playwright';

const STORYBOOK_URL = 'http://localhost:6006';
const SCREENSHOT_DIR = '/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/.storybook/screenshots';

const STORIES = [
  { id: 'screens-extract--loaded', name: 'extract-loaded', wait: 3000 },
  { id: 'screens-extract--empty', name: 'extract-empty', wait: 2000 },
  { id: 'screens-extract--loading', name: 'extract-loading', wait: 2000 },
  { id: 'screens-extract--error', name: 'extract-error', wait: 2000 },
];

async function main() {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 500, height: 900 } });

  for (const story of STORIES) {
    const url = `${STORYBOOK_URL}/iframe.html?id=${story.id}&viewMode=story`;
    console.log(`Navigating to ${story.name}...`);
    await page.goto(url, { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(story.wait);
    const path = `${SCREENSHOT_DIR}/${story.name}.png`;
    await page.screenshot({ path, fullPage: true });
    console.log(`  -> Saved ${path}`);
  }

  await browser.close();
  console.log('Done!');
}

main().catch(err => { console.error(err); process.exit(1); });
